stylesheet:
QWidget {
    background: #120c1c;
    color: #e0d4f0;
    font-family: "JetBrains Sans", "Segoe UI Variable", "Segoe UI", "Arial", "Noto Sans", sans-serif;
    font-size: 10pt;
}
#WindowShell {
    background: transparent;
}
QStackedWidget, QStackedWidget > QWidget, QWidget#PagesShell, QStackedWidget#PagesStack {
    background: transparent;
}
QWidget[class="pageRoot"], QWidget[class="pageCanvas"] {
    background: transparent;
}
QLabel {
    background: transparent;
}
#RootFrame {
    background: #161022;
    border: 1px solid #2a2040;
    border-radius: 16px;
}
#TitleBar {
    background: #161022;
    border: none;
    border-top-left-radius: 16px;
    border-top-right-radius: 16px;
}
#Sidebar {
    background: #161022;
    border-bottom-left-radius: 16px;
}
#Content {
    background: transparent;
    border: none;
}
#ContentSurface {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #120c1c, stop:0.62 #161022, stop:1 #1c1430);
    border-top: 1px solid #2a2040;
    border-left: 1px solid #2a2040;
    border-top-left-radius: 18px;
    border-top-right-radius: 0px;
    border-bottom-left-radius: 0px;
    border-bottom-right-radius: 16px;
}
QDialog#AppDialogWindow {
    background: transparent;
    border: none;
}
#DialogRoot {
    background: #1a1230;
    border: 1px solid #352a50;
    border-radius: 12px;
}
#DialogTitleBar {
    background: transparent;
    border: none;
    border-top-left-radius: 12px;
    border-top-right-radius: 12px;
}
#DialogBody {
    background: transparent;
}
#SettingsScroll, #SettingsCanvas, #SettingsScroll QWidget#qt_scrollarea_viewport {
    background: transparent;
    border: none;
}
QFrame[class="settingsSection"] {
    background: #1a1230;
    border: 1px solid #352a50;
    border-radius: 14px;
}
#LoadingOverlay {
    background: rgba(18, 12, 28, 0.6);
}
#LoadingCard {
    background: #1a1230;
    border: 1px solid #4a3a70;
    border-radius: 16px;
}
QFrame[class="card"] {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #161022, stop:0.68 #1a1230, stop:1 #20163c);
    border: 1px solid #2a2040;
    border-radius: 16px;
}
QFrame[class="modHero"] {
    background: qlineargradient(x1:0, y1:0, x2:1, y2:1, stop:0 #1c1430, stop:1 #161022);
    border: 1px solid #3a2e60;
    border-radius: 16px;
}
QFrame[class="modCard"] {
    background: #1a1230;
    border: 1px solid #352a50;
    border-radius: 16px;
}
QFrame#NotificationsPopup {
    background: #1a1230;
    border: 1px solid #3a2e60;
    border-radius: 14px;
}
QFrame[class="notificationCard"] {
    background: #20163c;
    border: 1px solid #3a2e60;
    border-radius: 12px;
}
QScrollArea#NotificationsScroll, QWidget#NotificationsCanvas {
    background: transparent;
    border: none;
}
QFrame[class="modIconWrap"] {
    background: #261d42;
    border: 1px solid #4a3a70;
    border-radius: 16px;
}
QLabel[class="title"] {
    font-size: 13pt;
    font-weight: 700;
    color: #f0ecfc;
}
#DashboardTitle {
    padding: 0px;
    margin: 0px;
}
#DashboardPowerBlock {
    background: transparent;
}
QLabel[class="muted"] {
    color: #b0a0d4;
}
QLabel[class="modHint"] {
    color: #c0b0e0;
}
QLabel[class="modState"] {
    color: #f0ecfc;
    background: #261d42;
    border: 1px solid #4a3a70;
    border-radius: 12px;
    padding: 6px 12px;
    font-weight: 600;
}
QLabel[class="modState"][state="enabled"] {
    background: rgba(80, 180, 120, 0.16);
    border: 1px solid #4d8b67;
    color: #a8efc1;
}
QLabel[class="modState"][state="installed"] {
    background: rgba(140, 100, 220, 0.16);
    border: 1px solid #8a6ad0;
    color: #d6c8ff;
}
QLabel[class="modState"][state="not installed"] {
    background: rgba(150, 130, 200, 0.08);
    border: 1px solid #5a4a80;
    color: #c0b0e0;
}
QLabel[class="modMeta"] {
    color: #b0a0d4;
    background: #1e1638;
    border: 1px solid #3a2e60;
    border-radius: 12px;
    padding: 6px 12px;
}
#ModsSummaryChip, #ModsEnabledChip {
    border-radius: 11px;
}
#ModStateBadge, #ModMetaChip {
    border-radius: 12px;
}
QLabel[class="modBody"] {
    color: #d8ccec;
    line-height: 1.3em;
}
#ModsScroll, #ModsCanvas, #ComponentsScroll, #ComponentsCanvas {
    background: transparent;
    border: none;
}
QToolButton[class="nav"] {
    min-width: 46px;
    min-height: 46px;
    max-width: 46px;
    max-height: 46px;
    border-radius: 12px;
    border: 1px solid transparent;
    background: transparent;
}
QToolButton[class="nav"]:hover {
    background: #2a2048;
    border: 1px solid #4a3a70;
}
QToolButton[class="nav"]:checked {
    background: #3a2e60;
    border: 1px solid #7a62c0;
}
QToolButton[class="window"] {
    min-width: 26px;
    min-height: 26px;
    max-width: 26px;
    max-height: 26px;
    border-radius: 12px;
    border: none;
    background: transparent;
    padding: 0px;
    margin: 0px;
}
QToolButton[class="window"][role="close"]:hover {
    background: rgba(170, 120, 220, 0.5);
}
QPushButton {
    background: #2a2048;
    border: 1px solid #4a3a70;
    border-radius: 10px;
    padding: 8px 12px;
}
#LogsFilesShell {
    background: #161022;
    border: 1px solid #2a2040;
    border-radius: 16px;
}
QTabBar::tab {
    background: #120c1c;
    border: 1px solid #3a2e60;
    border-radius: 8px;
    padding: 6px 16px;
    margin-right: 4px;
    color: #c0b0e0;
}
QTabBar::tab:selected {
    background: #8a6ad0;
    border-color: #aa88f0;
    color: #ffffff;
}
QTabBar::tab:hover:!selected {
    background: #2a2048;
}
QPushButton[class="settingsSegment"] {
    background: #120c1c;
    border: 1px solid #3a2e60;
    color: #c0b0e0;
}
QPushButton[class="settingsSegment"]:checked {
    background: #8a6ad0;
    color: #ffffff;
}
QToolButton[class="power"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #a07ee0, stop:0.48 #8a6ad0, stop:1 #6a4eb0);
    border: 2px solid #aa88f0;
}
QToolButton[class="power"][state="off"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #3a2e60, stop:0.55 #2a2048, stop:1 #1e1638);
    border: 2px solid #4a3a70;
}
QLineEdit, QComboBox, QTextEdit, QTableWidget {
    background: #120c1c;
    border: 1px solid #3a2e60;
    selection-background-color: #4a3a70;
}
QCheckBox::indicator {
    border: 1px solid #6a5a90;
    background: transparent;
}
QCheckBox::indicator:checked {
    border: 1px solid #aa88f0;
    background: #8a6ad0;
}
QListWidget {
    background: #120c1c;
    border: 1px solid #3a2e60;
}
QListWidget::item {
    background: #1a1230;
    border: 1px solid #352a50;
}
QListWidget::item:selected {
    background: #3a2e60;
    border: 1px solid #8a6ad0;
}
QHeaderView::section {
    background: #261d42;
    color: #e0d4f0;
}
QMenu {
    background: #1a1230;
    border: 1px solid #3a2e60;
}
QMenu::item:selected {
    background: #3a2e60;
}
